if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=$_POST['action']??'';$id=(int)($_POST['id']??0);if($action==='delete'){db()->prepare('DELETE FROM social_security_definitions WHERE id=?')->execute([$id]);$message='Tanım silindi.';}else{$name=trim($_POST['name']??'');$active=isset($_POST['active'])?1:0;$sort=(int)($_POST['sort_order']??0);if($name==='')$error='Tanım adı zorunludur.';else try{if($id)db()->prepare('UPDATE social_security_definitions SET name=?,active=?,sort_order=? WHERE id=?')->execute([$name,$active,$sort,$id]);else db()->prepare('INSERT INTO social_security_definitions(name,active,sort_order) VALUES(?,?,?)')->execute([$name,$active,$sort]);$message='Tanım kaydedildi.';}catch(PDOException $e){$error='Bu tanım zaten mevcut.';}}}
